var items = $input.all();
var results = [];
var now = new Date().toISOString();
for (var i = 0; i < items.length; i++) {
  var data = items[i].json;
  var title = data.title || data.name || 'Untitled';
  var link = data.link || data.url || data.guid || '';
  var summary = (data.contentSnippet || data.content || data.description || '').replace(/<[^>]*>/g,'').trim();
  var source = data.creator || data.author || 'Unknown';
  var published = data.pubDate || data.isoDate || data.date || now;
  var category = 'research-papers';
  var priority = 3;
  var text = (title + ' ' + summary).toLowerCase();
  if (/threat|advisory|advisori|vulnerabilit|cve|incident|attack|malware|breach|exploit/.test(text)) { category='threat-intelligence'; priority=1; }
  else if (/standard|policy|policies|guidance|framework|compliance|regulation|nist|iso/.test(text)) { category='standards-policy'; priority=2; }
  else if (/crypto|encryption|cipher|quantum|hash|tls|pki|certificate|key management/.test(text)) { category='cryptography'; priority=2; }
  else if (/gds|accessibility|wcag|design system|user research|service design|single.page|spa/.test(text)) { category='spa-design-gds'; priority=2; }
  results.push({json:{title:title,link:link,summary:summary.substring(0,300),source:source,published:published,category:category,priority:priority}});
}
results.sort(function(a,b){return a.json.priority - b.json.priority;});
return results;

var now = new Date().toLocaleDateString('en-GB',{weekday:'long',year:'numeric',month:'long',day:'numeric'});
var allItems = $('Categorise Documents').all();
var groups = {};
for (var i=0;i<allItems.length;i++){
  var c=allItems[i].json.category||'other';
  if(!groups[c])groups[c]=[];
  groups[c].push(allItems[i].json);
}
var labels={
  'threat-intelligence':'🚨 Threat Intelligence & Advisories',
  'standards-policy':'📋 Standards, Policy & Guidance',
  'cryptography':'🔐 Cryptography & Encryption',
  'spa-design-gds':'🏛️ SPA Design, GDS & Accessibility',
  'research-papers':'📄 Research Papers & Analysis',
  'other':'📌 Other'
};
var order=['threat-intelligence','standards-policy','cryptography','spa-design-gds','research-papers','other'];
var html='<div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;">';
html+='<div style="background:#003078;color:#fff;padding:20px;border-radius:6px 6px 0 0;">';
html+='<h1 style="margin:0;font-size:1.4em;">🔒 HMGCC SPA Research & Document Library</h1>';
html+='<p style="margin:5px 0 0;opacity:0.8;">'+now+'</p></div>';
for(var ci=0;ci<order.length;ci++){
  var cat=order[ci];
  var entries=groups[cat];
  if(!entries||!entries.length)continue;
  html+='<div style="padding:15px 20px;border-bottom:2px solid #eee;">';
  html+='<h2 style="color:#003078;font-size:1.1em;margin:0 0 10px;">'+(labels[cat]||cat)+' ('+entries.length+')</h2>';
  html+='<ul style="padding-left:20px;margin:0;">';
  for(var e=0;e<entries.length;e++){
    html+='<li style="margin-bottom:8px;">';
    html+='<strong><a href="'+entries[e].link+'" style="color:#003078;">'+entries[e].title+'</a></strong>';
    if(entries[e].summary)html+='<br><span style="color:#555;font-size:0.9em;">'+entries[e].summary.substring(0,200)+'</span>';
    html+='<br><small style="color:#999;">'+entries[e].source+'</small></li>';
  }
  html+='</ul></div>';
}
html+='<p style="color:#999;font-size:0.8em;padding:10px 20px;">Generated by Workhorse &bull; '+now+'</p></div>';
return [{json:{subject:'HMGCC SPA Research Digest — '+now,html:html,itemCount:allItems.length}}];
